const { GoogleGenerativeAI } = require('@google/generative-ai');
const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
const model = genAI.getGenerativeModel({ model: 'gemini-2.0-flash' });

const data1 = $('Parse HTML - Competidor 1').item;
const data2 = $('Parse HTML - Competidor 2').item;

const prompt = `Analiza estos 2 competidores:

Competidor 1:
Title: ${data1.json.title}
Desc: ${data1.json.description}
H1: ${data1.json.h1}

Competidor 2:
Title: ${data2.json.title}
Desc: ${data2.json.description}
H1: ${data2.json.h1}

Genera:
1. Comparativa de value props
2. Diferencias clave
3. Oportunidades de posicionamiento`;

const result = await model.generateContent(prompt);
return { json: { analysis: result.response.text() } };
